def conv2d_flops(N: int, C_in: int, C_out: int, H_out: int, W_out: int,
                  kH: int, kW: int) -> int:
    return 2 * N * C_out * H_out * W_out * C_in * kH * kW

def linear_flops(N: int, in_features: int, out_features: int) -> int:
    return 2 * N * in_features * out_features

def pool2d_flops(N: int, C: int, H_out: int, W_out: int,
                  kH: int, kW: int) -> int:
    return N * C * H_out * W_out * kH * kW

def count_model_flops(layers: list) -> int:
    total = 0
    for layer in layers:
        t = layer['type']
        if t == 'conv2d':
            total += conv2d_flops(layer['N'], layer['C_in'], layer['C_out'],
                                   layer['H_out'], layer['W_out'],
                                   layer['kH'], layer['kW'])
        elif t == 'linear':
            total += linear_flops(layer['N'], layer['in_features'], layer['out_features'])
        elif t == 'pool2d':
            total += pool2d_flops(layer['N'], layer['C'], layer['H_out'], layer['W_out'],
                                   layer['kH'], layer['kW'])
    return total
